namespace sv_5ccda45761ad460ba2bfdab703cfb2ef.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single circuit.
/// Components subscribe to OnChange to react when the user switches warehouses.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new("wh-1", "Warehouse A – East"),
        new("wh-2", "Warehouse B – West"),
        new("wh-3", "Warehouse C – Central"),
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _selectedWarehouseId)?.Name
        ?? _selectedWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId)
            return;

        _selectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public record WarehouseInfo(string Id, string Name);

namespace sv_5ccda45761ad460ba2bfdab703cfb2ef.Services;

/// <summary>
/// Scoped service that simulates checking for low-stock items.
/// Fires OnAlertCountChanged so every subscribed component re-renders,
/// even components that did not initiate the poll.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database query – return a random number 0–15.
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Called by the component that owns the polling timer.
    /// Updates the cached count and notifies ALL subscribers.
    /// </summary>
    public void PublishCount(int count)
    {
        CurrentCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

namespace sv_5ccda45761ad460ba2bfdab703cfb2ef.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single circuit.
/// Components subscribe to OnChange to react when the user switches warehouses.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new("wh-1", "Warehouse A – East"),
        new("wh-2", "Warehouse B – West"),
        new("wh-3", "Warehouse C – Central"),
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _selectedWarehouseId)?.Name
        ?? _selectedWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId)
            return;

        _selectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public record WarehouseInfo(string Id, string Name);

