+
+<div class="warehouse-selector">
+    <label class="warehouse-label" for="warehouseSelect">Warehouse:</label>
+    <select id="warehouseSelect"
+            class="form-select form-select-sm"
+            value="@WarehouseState.SelectedWarehouseId"
+            @onchange="OnWarehouseChanged">
+        @foreach (var wh in WarehouseState.AvailableWarehouses)
+        {
+            <option value="@wh.Id">@wh.Name</option>
+        }
+    </select>
+</div>
+
+@code {
+    /// <summary>
+    /// Injected CascadingValueSource so we can push warehouse changes across render-mode boundaries.
+    /// </summary>
+    [Inject]
+    private CascadingValueSource<string> WarehouseIdSource { get; set; } = default!;
+
+    private Action? _handler;
+
+    protected override void OnInitialized()
+    {
+        // Re-render this component when another component changes the warehouse.
+        _handler = () => InvokeAsync(StateHasChanged);
+        WarehouseState.OnChange += _handler;
+    }
+
+    private async Task OnWarehouseChanged(ChangeEventArgs e)
+    {
+        var newId = e.Value?.ToString();
+        if (string.IsNullOrEmpty(newId))
+            return;
+
+        WarehouseState.SetWarehouse(newId);
+
+        // Push to CascadingValueSource so [CascadingParameter] subscribers update.
+        await WarehouseIdSource.NotifyChangedAsync(newId);
+    }
+
+    public void Dispose()
+    {
+        WarehouseState.OnChange -= _handler;
+    }
+}
