@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IAsyncDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<h4 class="text-muted mb-4">@WarehouseState.SelectedWarehouseName</h4>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertService.CurrentCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.CurrentCount
                </p>
                <p class="text-muted">
                    items below minimum level
                </p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="display-6">@WarehouseState.SelectedWarehouseName</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6">
                    <span class="badge bg-success">Active</span>
                </p>
                <p class="text-muted">every 10 seconds</p>
            </div>
        </div>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    /// <summary>
    /// Receives the current warehouse ID via CascadingValueSource (crosses render-mode boundary).
    /// When the user picks a new warehouse in the static layout, this updates automatically.
    /// </summary>
    [CascadingParameter]
    private string? CurrentWarehouseId { get; set; }

    protected override void OnInitialized()
    {
        // Subscribe to warehouse changes so we restart polling for the new warehouse.
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        WarehouseState.OnChange += _warehouseHandler;

        // Subscribe to alert updates so the dashboard re-renders when new data arrives.
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _alertHandler;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async Task OnWarehouseChanged()
    {
        StopPolling();
        await PollOnceAsync();
        await StartPollingAsync();
        StateHasChanged();
    }

    private async Task StartPollingAsync()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        // Fetch immediately on start.
        await PollOnceAsync();

        _ = RunPollingLoopAsync(_cts.Token);
    }

    private async Task RunPollingLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () =>
                {
                    await PollOnceAsync();
                });
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when navigating away or switching warehouses.
        }
    }

    private async Task PollOnceAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);
        // Publish to service – this fires OnAlertCountChanged and updates ALL subscribers
        // (sidebar badge, this page, etc.) in one shot.
        AlertService.PublishCount(count);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public async ValueTask DisposeAsync()
    {
        StopPolling();

        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;

        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

